from typing import List, Dict, Any, Optional, Callable
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict

def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    if not search_results:
        return {}

    # Initialize aggregations dictionary
    aggregations = defaultdict(lambda: {
        "count": 0,
        "sum_scores": 0.0,
        "max_score": float('-inf'),
        "min_score": float('inf'),
        "custom_aggregations": {}
    })

    # Helper function to safely extract field value
    def get_field_value(result: SearchResult, field: str) -> Any:
        """Extract field value from result, checking both top-level and metadata."""
        # Check top-level fields first
        if hasattr(result, field):
            return getattr(result, field)
        # Then check metadata
        return result.metadata.get(field)

    # Iterate through each search result
    for result in search_results:
        # Extract group value from metadata
        group_value = result.metadata.get(group_by_field)

        # Handle missing group field values
        if group_value is None or group_value == "":
            group_key = "unknown"
        else:
            group_key = str(group_value)

        # Collect statistics for default calculations
        score = result.score
        group_data = aggregations[group_key]

        # Update count and sum for average calculation
        group_data["count"] += 1
        group_data["sum_scores"] += score

        # Update max and min scores
        if score > group_data["max_score"]:
            group_data["max_score"] = score
        if score < group_data["min_score"]:
            group_data["min_score"] = score

        # Collect values for custom aggregation functions
        if aggregation_funcs:
            for field_name, func in aggregation_funcs.items():
                field_value = get_field_value(result, field_name)
                # Only process non-None values for aggregation
                if field_value is not None:
                    # Initialize list if this is the first occurrence
                    if field_name not in group_data["custom_aggregations"]:
                        group_data["custom_aggregations"][field_name] = []
                    group_data["custom_aggregations"][field_name].append(field_value)

    # Calculate final statistics for each group
    final_aggregations = {}
    for group_key, data in aggregations.items():
        # Calculate average score
        avg_score = data["sum_scores"] / data["count"] if data["count"] > 0 else 0.0

        # Apply custom aggregation functions if available
        custom_results = {}
        if aggregation_funcs and "custom_aggregations" in data:
            for field_name, values in data["custom_aggregations"].items():
                try:
                    custom_results[field_name] = aggregation_funcs[field_name](values)
                except Exception as e:
                    # Log error or handle gracefully
                    custom_results[field_name] = f"Error: {str(e)}"

        # Combine all statistics
        group_stats = {
            "count": data["count"],
            "avg_score": round(avg_score, 4),
            "max_score": round(data["max_score"], 4),
            "min_score": round(data["min_score"], 4)
        }

        # Add custom aggregations if they exist
        if custom_results:
            group_stats.update(custom_results)

        final_aggregations[group_key] = group_stats

    return final_aggregations

